 12→import { mkdirSync, mkdtempSync, rmSync } from "node:fs";
 13→import { tmpdir } from "node:os";
 14→import { join } from "node:path";
 15→import type { Subprocess } from "bun";
 16→
 17→let apiProcess: Subprocess;
 18→let apiPort: number;
 19→let apiBaseUrl: string;
 20→let tempDir: string;
 21→let configDir: string;
 22→let sessionToken: string;
