 24→async function waitForServer(url: string, timeoutMs = 10_000): Promise<void> {
 25→	const deadline = Date.now() + timeoutMs;
 26→	while (Date.now() < deadline) {
 27→		try {
 28→			const res = await fetch(url, {
 29→				method: "POST",
 30→				headers: { "Content-Type": "application/json" },
 31→				body: "{}",
 32→			});
 33→			if (res.ok) return;
 34→		} catch {
 35→			// not ready yet
 36→		}
 37→		await Bun.sleep(100);
 38→	}
 39→	throw new Error(`Server at ${url} did not start within ${timeoutMs}ms`);
 40→}
 41→
 42→beforeAll(async () => {
 43→	// Create temp directories
 44→	tempDir = mkdtempSync(join(tmpdir(), "rudel-auth-test-"));
 45→	configDir = join(tempDir, "config");
 46→	mkdirSync(configDir, { recursive: true });
 47→
 48→	// Create data dir for SQLite DB
 49→	const dataDir = join(tempDir, "data");
 50→	mkdirSync(dataDir, { recursive: true });
 51→
 52→	// Find a free port by briefly binding
 53→	const tempServer = Bun.serve({
 54→		port: 0,
 55→		hostname: "127.0.0.1",
 56→		fetch: () => new Response(""),
 57→	});
 58→	apiPort = tempServer.port as number;
 59→	tempServer.stop(true);
 60→
 61→	apiBaseUrl = `http://localhost:${apiPort}`;
 62→
 63→	// Start real API server with test PORT and working directory
 64→	const apiEntrypoint = join(
 65→		import.meta.dir,
 66→		"..",
 67→		"..",
 68→		"..",
 69→		"api",
 70→		"src",
 71→		"index.ts",
 72→	);
 73→	apiProcess = Bun.spawn(["bun", apiEntrypoint], {
 74→		env: {
 75→			...process.env,
 76→			PORT: String(apiPort),
 77→		},
 78→		cwd: tempDir,
 79→		stdout: "ignore",
 80→		stderr: "ignore",
 81→	});
 82→
 83→	// Wait for server to be ready
 84→	await waitForServer(`${apiBaseUrl}/rpc/health`, 15_000);
 85→
 86→	// Create a test user via sign-up and extract session token
 87→	const signupResponse = await fetch(`${apiBaseUrl}/api/auth/sign-up/email`, {
 88→		method: "POST",
 89→		headers: { "Content-Type": "application/json" },
 90→		body: JSON.stringify({
 91→			name: "Test User",
 92→			email: "test@example.com",
 93→			password: "testpassword123",
 94→		}),
 95→	});
 96→
 97→	expect(signupResponse.ok).toBe(true);
 98→
 99→	// Extract session token from response body
100→	const signupData = (await signupResponse.json()) as { token: string };
101→	sessionToken = signupData.token;
102→});
103→
104→afterAll(async () => {
105→	if (apiProcess) {
106→		apiProcess.kill();
107→		await apiProcess.exited;
108→	}
109→	rmSync(tempDir, { recursive: true, force: true });
110→});
111→
112→describe("auth e2e", () => {
113→	test("login: callback server receives token and stores credentials", async () => {
114→		// Clear any existing credentials first
115→		clearCredentialsFromDir(configDir);
116→
117→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
118→		const stdoutLogPath = join(tempDir, "login-stdout.log");
119→
120→		// Start login via shell, tee stdout to a file so we can poll it
121→		const loginProcess = Bun.spawn(
122→			[
123→				"bash",
124→				"-c",
125→				`bun "${cliPath}" login --api-base="${apiBaseUrl}" --web-url=http://localhost:9999 2>&1 | tee "${stdoutLogPath}"`,
126→			],
127→			{
128→				env: {
129→					...process.env,
130→					RUDEL_CONFIG_DIR: configDir,
131→				},
132→				stdout: "pipe",
133→				stderr: "pipe",
134→			},
135→		);
136→
137→		// Poll the log file for the "Opening browser" message
138→		const { readFileSync, existsSync } = require("node:fs");
139→		let output = "";
140→		const deadline = Date.now() + 10_000;
141→
142→		while (Date.now() < deadline) {
143→			if (existsSync(stdoutLogPath)) {
144→				output = readFileSync(stdoutLogPath, "utf-8");
145→				if (output.includes("Opening browser")) break;
146→			}
147→			await Bun.sleep(100);
148→		}
149→
150→		// Extract the callback URL from the output
151→		const callbackMatch = output.match(/cli_callback=([^&]+)/);
152→		expect(callbackMatch).not.toBeNull();
153→		const callbackUrl = decodeURIComponent(callbackMatch?.[1] ?? "");
154→
155→		// Extract the state
156→		const stateMatch = output.match(/state=([a-f0-9]+)/);
157→		expect(stateMatch).not.toBeNull();
158→		const state = stateMatch?.[1] ?? "";
159→
160→		// Simulate what the web app does: hit the callback with token + state
161→		const callbackResponse = await fetch(
162→			`${callbackUrl}?token=${sessionToken}&state=${state}`,
163→		);
164→		expect(callbackResponse.ok).toBe(true);
165→		const callbackBody = await callbackResponse.text();
166→		expect(callbackBody).toContain("Login successful");
167→
168→		// Wait for the process to finish
169→		const exitCode = await loginProcess.exited;
170→		expect(exitCode).toBe(0);
171→
172→		// Verify credentials were stored
173→		const savedCredentials = loadCredentialsFromDir(configDir);
174→		expect(savedCredentials).not.toBeNull();
175→		expect(savedCredentials?.token).toBe(sessionToken);
176→		expect(savedCredentials?.apiBaseUrl).toBe(apiBaseUrl);
177→	});
