179→	test("whoami: shows user info with valid credentials", async () => {
180→		// Ensure credentials are stored
181→		saveCredentialsToDir(configDir, sessionToken, apiBaseUrl);
182→
183→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
184→		const proc = Bun.spawn(["bun", cliPath, "whoami"], {
185→			env: {
186→				...process.env,
187→				RUDEL_CONFIG_DIR: configDir,
188→			},
189→			stdout: "pipe",
190→			stderr: "pipe",
191→		});
192→
193→		const exitCode = await proc.exited;
194→		const stdout = await new Response(proc.stdout).text();
195→		const stderr = await new Response(proc.stderr).text();
196→
197→		expect(exitCode).toBe(0);
198→		expect(stdout).toContain("Test User");
199→		expect(stdout).toContain("test@example.com");
200→		expect(stderr).toBe("");
201→	});
