203→	test("logout: clears credentials", async () => {
204→		// Ensure credentials exist
205→		saveCredentialsToDir(configDir, sessionToken, apiBaseUrl);
206→
207→		const cliPath = join(import.meta.dir, "..", "bin", "cli.ts");
208→		const proc = Bun.spawn(["bun", cliPath, "logout"], {
209→			env: {
210→				...process.env,
211→				RUDEL_CONFIG_DIR: configDir,
