import { createClickHouseExecutor } from "@chkit/clickhouse";

type ClickHouseExecutor = ReturnType<typeof createClickHouseExecutor>;

let _clickhouse: ClickHouseExecutor | null = null;

export function getClickhouse(): ClickHouseExecutor {
	if (!_clickhouse) {
		_clickhouse = createClickHouseExecutor({
			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
			username:
				process.env.CLICKHOUSE_USERNAME ||
				process.env.CLICKHOUSE_USER ||
				"default",
			password: process.env.CLICKHOUSE_PASSWORD || "",
			database: "default",
		});
	}
	return _clickhouse;
}

content.thinking:
Ah, I see. The ingest endpoint calls ClickHouse which is an external service. In the worker environment, the ClickHouse env vars are bridged from the worker env to `process.env` in `worker.ts`:

```typescript
process.env.CLICKHOUSE_URL = env.CLICKHOUSE_URL;
process.env.CLICKHOUSE_USERNAME = env.CLICKHOUSE_USERNAME;
process.env.CLICKHOUSE_PASSWORD = env.CLICKHOUSE_PASSWORD;
```

But the issue is that in the wrangler dev environment, `process.env` access in the worker is different from Node.js. 

So the env vars should flow from `.dev.vars` through the worker bindings and get bridged to `process.env`. The 500 error is likely coming from ClickHouse itself — either the CI server isn't reachable from my local environment, a required table doesn't exist, or there's another ClickHouse-related failure happening.

The old tests that spawned the API directly had the same issue, which suggests these tests might have been broken before. Looking at the `index.ts` file, it imports a router that might have a different ingest handler that doesn't rely on ClickHouse, so I should check what that router actually exports.

